const report = $('Check Key Ages').first().json.report;
const rows = report.rows || [];
const urgencyColor = (u) => u === 'high' ? '#c0392b' : (u === 'medium' ? '#e67e22' : '#27ae60');
const urgencyLabel = (u) => u === 'high' ? 'CRITICA (>90 dias)' : (u === 'medium' ? 'Recomendada (>60 dias)' : 'OK');
const rowsHtml = rows.map(r => {
  return `<tr><td>${r.key}</td><td>${r.days_old} dias</td><td style="color:${urgencyColor(r.urgency)};font-weight:bold">${urgencyLabel(r.urgency)}</td><td>${(r.updated_at || '').slice(0,10)}</td></tr>`;
}).join('');
const html = `<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto">
<h2 style="color:${report.any_high ? '#c0392b' : '#e67e22'}">Recordatorio: rotacion de claves de seguridad</h2>
<p>Han pasado mas de 60 dias desde la ultima rotacion de algunas claves del sistema. Por buenas practicas (y antes de un eventual leak), conviene rotarlas.</p>
<table border="1" cellspacing="0" cellpadding="6" style="border-collapse:collapse;width:100%">
  <thead style="background:#f4f4f4"><tr><th>Clave</th><th>Antiguedad</th><th>Urgencia</th><th>Ultima rotacion</th></tr></thead>
  <tbody>${rowsHtml}</tbody>
</table>
<h3>Procedimiento de rotacion (manual)</h3>
<ol>
<li><b>webhook_api_key</b>: generar uno nuevo (<code>openssl rand -base64 32</code>), actualizar credencial 'ArquitAI Webhook API Key' en n8n, actualizar valor en system_config, y comunicarlo a integradores externos (DocuSign, formularios cliente).</li>
<li><b>encryption_key</b>: requiere descifrar primero todas las columnas _enc con clave vieja, cambiar la clave en system_config, re-cifrar (ver migration 008 nota "Rotacion de la clave de cifrado").</li>
<li><b>docusign/signaturit_webhook_secret</b>: regenerar en el panel del proveedor + actualizar en system_config.</li>
</ol>
<p style="color:#7f8c8d;font-size:12px">Este recordatorio se envia automaticamente cada 1 de mes a las 09:00. Solo llega si hay alguna clave >60 dias.</p>
</div>`;
return [{ json: { html: html, subject: report.any_high ? '[ARQUITAI ALERTA] Rotar claves >90 dias' : '[ArquitAI] Recordatorio rotacion claves' } }];
